#!/usr/bin/env python3
"""mesh-bench.py — benchmark the resilient R1 /chain mesh (latency + throughput).

Measures, against one or more ENTRY-stage nodes, the end-to-end /chain time for a
fixed prefill (entry embed + layers -> WiFi relay -> exit layers + lm-head -> logits)
and the throughput gain from issuing requests concurrently across the entry replicas
(data-parallel pipelines + per-node batching).

ALWAYS label cold vs warm: the first request is cold; battery-released devices throttle
vs plugged-in, so note the power state when reporting.

Usage:
  mesh-bench.py --entries 10.0.0.199,10.0.0.196 [--port 8090] [--n 16] [--warm 8]
                [--tokens 785,6722,315,9625,374] [--expect 12095]
"""
import argparse, struct, sys, threading, time, urllib.request


def chain(ip, port, body):
    r = urllib.request.Request(f"http://{ip}:{port}/chain", data=body, method="POST")
    r.add_header("X-Position", "0")
    t = time.time()
    raw = urllib.request.urlopen(r, timeout=120).read()
    dt = (time.time() - t) * 1000.0
    lg = struct.unpack("<%df" % (len(raw) // 4), raw)
    return dt, max(range(len(lg)), key=lambda i: lg[i])


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--entries", required=True, help="comma-separated entry-node IPs")
    ap.add_argument("--port", type=int, default=8090)
    ap.add_argument("--n", type=int, default=16, help="requests for the throughput test")
    ap.add_argument("--warm", type=int, default=8, help="warm samples per entry")
    ap.add_argument("--tokens", default="785,6722,315,9625,374")
    ap.add_argument("--expect", type=int, default=12095)
    a = ap.parse_args()
    entries = [e.strip() for e in a.entries.split(",") if e.strip()]
    toks = [int(x) for x in a.tokens.split(",")]
    body = struct.pack("<%dI" % len(toks), *toks)

    print(f"== latency ({len(toks)}-token prefill -> logits, entry->exit) ==")
    dt, am = chain(entries[0], a.port, body)
    print(f"  COLD ({entries[0]}, first): {dt:.0f} ms  argmax={am} {'ok' if am==a.expect else 'BAD'}")
    for ip in entries:
        xs = [chain(ip, a.port, body) for _ in range(a.warm)]
        ms = [d for d, _ in xs]
        ok = all(x == a.expect for _, x in xs)
        print(f"  WARM {ip} x{a.warm}: mean {sum(ms)/len(ms):.0f}  min {min(ms):.0f}  max {max(ms):.0f} ms  all-expect={ok}")

    print(f"== throughput: {a.n} requests, sequential vs concurrent across {len(entries)} pipeline(s) ==")
    t0 = time.time()
    for i in range(a.n):
        chain(entries[i % len(entries)], a.port, body)
    seq = time.time() - t0
    res = []
    def w(i):
        res.append(chain(entries[i % len(entries)], a.port, body))
    t0 = time.time()
    ths = [threading.Thread(target=w, args=(i,)) for i in range(a.n)]
    [t.start() for t in ths]
    [t.join() for t in ths]
    conc = time.time() - t0
    okc = all(x == a.expect for _, x in res)
    print(f"  sequential: {seq:.1f}s = {a.n/seq:.2f} req/s")
    print(f"  concurrent: {conc:.1f}s = {a.n/conc:.2f} req/s   speedup {seq/conc:.2f}x   all-expect={okc}")
    return 0 if okc else 1


if __name__ == "__main__":
    sys.exit(main())
